import {Charset} from "@/types/Charset";
import MailOptions from "@/types/MailOptions";
import {formatWebVersionFolder, getWebVersionText} from "@/utils/helpers";
import composeTrackingHtml from "@/utils/composeTrackingHtml";

export const EMAIL_DOCTYPE = "<!DOCTYPE HTML PUBLIC \"-//W3C//DTD HTML 4.01 Transitional//EN\"><html>";

export const emailHeader = (charset: Charset, title = "Swedbank") =>
    `<head>
    <meta http-equiv="content-type" content="text/html; charset=${charset}" />
    <meta name="viewport" content="width=device-width,initial-scale=1" />
    <title>${title}</title>
    <style type="text/css">
      @media only screen and (max-width: 480px) {
        .row-height {
          padding: 12px 0 !important;
        }
        .full {
          width: 100% !important;
        }
        u + .body .gwfw {
          width: 100% !important;
          width: 100vw !important;
        }

      }
      @media only screen and (max-width: 615px) {
        .table-width-mobile{
            width:100%;
            max-width: 415px!important;
            margin-left: 0!important;
            margin-right: 0!important;
          }
        .td-width-mobile{
            width:100%;
            width:375px;
          }
        .td-height-mobile{
          height:auto!important;
        }
      }
      span a, .full{
        text-decoration:none;
      }
    </style>
    <!--[if mso]>
    <style>
      .dark-mode-btn-text {
        mso-style-textfill-type:gradient;
        mso-style-textfill-fill-gradientfill-stoplist:"0 \\#FFFFFF 0 100000\\,100000 \\#FFFFFF 0 100000";
        color:#000000 !important;
      }
    </style>
    <![endif]-->
    </head>`;

export const headline = (text: string) => `<div style="height:1px;line-height:1px;display:none;color:#fbf2ea;font-size:1px;">${text}</div>`;

export const periodicalHeader = (webVersion: boolean, mailOptions: MailOptions) =>
    `\n<!-- Date and month Starts -->
         <table width="600" border="0" cellpadding="0" cellspacing="0" style="width:100%;max-width:600px;font-family:Roboto,sans-serif;font-size:14px;line-height:22px;color:#512b2b;background-color:#FFFFFF;">
           <tr>
             <td width="600" height="30" style="font-family:Roboto,sans-serif;font-size:14px;line-height:22px;color:#785F5F;">
               ${mailOptions.date}${!webVersion && mailOptions.web_location ? `&nbsp;&nbsp;|&nbsp;&nbsp; <a href="${formatWebVersionFolder(mailOptions.web_location)}/index_${mailOptions.language.toLowerCase()}.html" target="_blank" style="font-family:Roboto,sans-serif;font-size:14px;color:#257886;text-decoration:underline;">${getWebVersionText(mailOptions.language)}</a>` : ""}
             </td>
           </tr>
         </table>
         <!-- Date and month Ends -->`;

export const emailBody = (periodical: boolean, headlineText: string | null) =>
    `<body bgcolor="#FFFFFF" style="padding:0;margin:0;background-color:#FFFFFF;" class="body">
<table width="100%" border="0" cellpadding="0" cellspacing="0" style="width:100%;padding:0;margin:0;background-color:#FFFFFF;" class="gwfw">
    <tr>
        <td colspan="3" height="8" style="line-height:8px;">
            <center>
              ${periodical && headlineText !== null ? headline(headlineText) : ''}
            </center>
        </td>
    </tr>
    <tr>
        <td width="10">&nbsp;</td>
        <td align="center">
    
        <!-- Container Starts -->
        <table border="0" cellpadding="0" cellspacing="0" style="max-width:600px;">
            <tr>
                <td width="600" style="padding-top:20px;padding-bottom:20px;">`

export const MAIN_CONTAINER_START =
    `</table>
      <!-- Main Content Container 600 Starts -->
      <table width="600" border="0" cellpadding="0" cellspacing="0" style="width:100%;max-width:600px;font-family:Roboto,sans-serif;font-size:15px;color:#512b2b;background-color:#ffffff;">
        <tr>
          <td align="center" width="600" style="padding-bottom:20px;">`;

export const MAIN_END = `</td>
                </tr>
                </table>
                <!-- Main Content Container 600 Ends -->`;

export const emailEnd = (mailOptions: MailOptions, webVersion: boolean) =>
    `</td></tr></table><!-- Container Ends --></td><td width="10">&nbsp;</td></tr></table>
     ${webVersion ? '' : composeTrackingHtml(mailOptions)}
     </body></html>`