import TipTap from "@/types/TipTap";

class TABLE {
  header?: string;
  rows?: string[][]
}

// TODO: Combine with getBulletPoints
function parseParagraph(json: TipTap[] | undefined): string {
  let htmlString = '';
  if (!json || json[0].content?.length === 0) return '';
  json.forEach((paragraph) => {
    paragraph.content?.forEach((item) => {
      if (!item.marks) htmlString += item.text;
      else {
        let textStart = "";
        let textEnd = "";
        item.marks.forEach(mark => {
          const type = mark.type;
          switch (type) {
            case "italic":
              textStart += '<i>';
              textEnd += '</i>'
              break;
            case "bold":
              textStart += '<strong>';
              textEnd += '</strong>'
              break;
            case "link":
              textStart += `<a href="${mark.attrs?.href}" style="font-family:Roboto,sans-serif;font-size:15px;color:#257886;text-decoration:underline;" target="_blank">`;
              textEnd += '</a>'
              break;
            case "subscript":
              textStart += '<sub>';
              textEnd += '</sub>'
              break;
            case "superscript":
              textStart += '<sup>';
              textEnd += '</sup>'
              break;
            case "textStyle":
              if (mark.attrs?.color === "rgb(237, 125, 49)" || mark.attrs?.color === "#fb4f00" ||
                  mark.attrs?.color.color === "rgb(237, 125, 49)" || mark.attrs?.color.color === "#fb4f00") {
                textStart += '<span style="color: #fb4f00">';
                textEnd += '</span>'
              }
              break;
          }
        });
        htmlString += textStart + item.text + textEnd;
      }
    })
  })
  return htmlString;
}

export default function getTable (json: TipTap): TABLE {
  const tableClass: TABLE = { header: '', rows: []};
  if (!json.content || json.content.length === 0) return tableClass;
  json.content.forEach(table => {
    if (table.type !== 'table') return;
    table.content?.forEach((tableRow) => {
      if (!tableRow.content) return;
      const tableCells = [];
      for (const item of tableRow.content) {
        if (item.type === 'tableHeader' && !tableClass.header) tableClass.header = parseParagraph(item.content)
        else if (item.type === 'tableCell') tableCells.push(parseParagraph(item.content))
      }
      tableClass.rows!.push(tableCells)
    })
  })
  return tableClass;
}
