import {Country} from "@/types/Country";
import {Language} from "@/types/Language";
import {MessageCategory} from "@/types/MessageCategory";

export default class MailOptions {

    new_MCR: boolean;
    MCR: number; // mcr number, used for links
    country: Country; // for which country this email is for
    language: Language; // which language this email will be in
    business: boolean; // private or corporate
    messageCategory: MessageCategory | null; // determines tracking pixels
    periodical: boolean; // determines whether month and web version get added up left
    date: string | null; // used for periodical mails, e.g. "August 2022"
    headline: string | null; // if periodical, use headline
    web_location: string | null; // where the web version will be stored. used in the date next to the link

    constructor(new_MCR: boolean, MCR: number, country: Country, language: Language, business: boolean, messageCategory: MessageCategory | null, date: string | null, headline: string | null, periodical: boolean, web_location: string | null) {
        this.new_MCR = new_MCR;
        this.MCR = MCR;
        this.country = country;
        this.language = language;
        this.business = business;
        this.messageCategory = messageCategory;
        this.date = date;
        this.headline = headline;
        this.periodical = periodical;
        this.web_location = web_location;
    }

}

export const COUNTRIES = [Country.EE, Country.LV, Country.LT];
export const LANGUAGES = [Language.EST, Language.ENG, Language.RUS, Language.LAT, Language.LIT];
export const EE_LANGUAGES = [Language.EST, Language.ENG, Language.RUS];
export const LV_LANGUAGES = [Language.LAT, Language.ENG, Language.RUS];
export const LT_LANGUAGES = [Language.LIT, Language.ENG, Language.RUS];
export const MESSAGE_CATEGORIES = [MessageCategory.DirectMarketing, MessageCategory.ServiceComm, MessageCategory.FeedbackGathering];
