import {Element_Type} from "@/types/elements/ElementTypes";

export default function verifyImageSize(elementType: Element_Type, imageSize: string) {
  if (!imageSize) return false;
  if (elementType === Element_Type.IMAGE) {
    return (["1200x500", "1200x300", "1080x500", "1080x300"].includes(imageSize));
  } else if (elementType === Element_Type.SIGNATURE) {
    return (["180x180", "90x90", "270x270"].includes(imageSize));
  } else if (elementType === Element_Type.PARTNER_OFFER) {
    return (["208x208"].includes(imageSize));
  } else if (elementType === Element_Type.OFFER) {
    return (["300x300", "320x320", "500x500"].includes(imageSize));
  } else if (elementType === Element_Type.INTRO) {
    return (["180x180", "360x360"].includes(imageSize));
  }
}
