import {Element_Type} from "@/types/elements/ElementTypes";
import {defaultElements} from "@/types/defaults/DefaultElements";
import Element from "@/types/elements/Element";
import LANGUAGE_DEFAULTS from "@/types/defaults/LanguageDefaults";
import {Country} from "@/types/Country";
import {Language} from "@/types/Language";
import generateId from "@/utils/generateId";

const COLOR_BLOCK_DEFAULT_IMAGE_URL = "https://www.swedbank.ee/proinfo-files/email_example-image_1120x500_2.jpg"

/**
 * Create an Element instance with populated data based on user's selected language and country.
 * @param {Element_Type} elementType - The type of element to create.
 * @param {Language} language - The target language code.
 * @param {Country} country - The target country code.
 * @param {Element_Type} parentType - The element type of element's parent element, if there is one.
 * @returns {Element} The populated Element instance.
 */
export default function createElement(elementType: Element_Type, language: Language, country: Country, parentType?: Element_Type): Element {
  const defaultElement = <Element>{...structuredClone(defaultElements[elementType]), id: generateId()};

  // Recursively populate sub-elements
  if (defaultElement.subElements) {
    defaultElement.subElements = defaultElement.subElements.map(element => createElement(element.type, language, country, elementType));
  }
  if (defaultElement.type === Element_Type.TWO_COLUMNS) {
    defaultElement.subElements?.forEach((column) => {
      column.subElements?.forEach(element => createElement(element.type, language, country, elementType))
    });
  }

  return populateElement(defaultElement, language, country, parentType);
}

function populateElement(element: Element, language: Language, country: Country, parentType?: Element_Type): Element {
  // Handle default text for common element types
  if ([Element_Type.INTRO, Element_Type.SIGNATURE, Element_Type.TEXT, Element_Type.BUTTON, Element_Type.LINK].includes(element.type)) {
    const defaultStrings = LANGUAGE_DEFAULTS[element.type];
    if (language in defaultStrings) element.options.text = defaultStrings[language];
  }

  // Handle specific element types
  switch (element.type) {
    case Element_Type.OFFER_HEADER: {
      const defaults = LANGUAGE_DEFAULTS[element.type];
      element.options.title = defaults.title[language];
      element.options.text = defaults.text[language];
      break;
    }
    case Element_Type.LINK_AND_BUTTON: {
      const defaults = LANGUAGE_DEFAULTS[element.type];
      element.options.linkText = defaults[language];
      element.options.buttonText = defaults[language];
      break;
    }
  }

  // Apply parent-specific customizations
  if (parentType) {
    if (element.type === Element_Type.HEADING) element.options.text = "Heading";
    if (element.type === Element_Type.IMAGE) element.options.imageUrl = COLOR_BLOCK_DEFAULT_IMAGE_URL;
  }

  updateEmailUrlsForCountry(element, country);

  return element;
}

/**
 * Update URLs in an email element with the correct country domain.
 * @param {Element} element - The email element to update.
 * @param {string} country - The target country code.
 */
function updateEmailUrlsForCountry(element: Element, country: Country): void {
  if (element.type === Element_Type.TWO_COLUMNS) return;
  const urlKeys = ["url", "link", "imageUrl", "buttonUrl", "linkUrl"];
  for (const key of urlKeys) {
    if (element.options[key]) element.options[key] = element.options[key].replace("swedbank.ee", `swedbank.${country.toLowerCase()}`);
  }
}


