import {Element_Type} from "@/types/elements/ElementTypes";

/**
 * Determines whether a given element type can be nested within another element.
 *
 * Certain element types (e.g., LOGO, DISCLAIMER, TWO_COLUMNS) are considered top-level only
 * and cannot be nested. This function returns `false` for those types and `true` otherwise.
 *
 * @param {Element_Type} type - The type of the element to check.
 * @returns {boolean} `true` if the element type can be nested; `false` otherwise.
 */
export function canElementBeNested (type: Element_Type): boolean {
  return ![
    Element_Type.COLOR_BLOCK,
    Element_Type.DISCLAIMER,
    Element_Type.INTRO,
    Element_Type.LOGO,
    Element_Type.OFFER_HEADER,
    Element_Type.OFFER,
    Element_Type.PARTNER_OFFER,
    Element_Type.TWO_COLUMNS
  ].includes(type);
}