<template>
  <div>
    <v-textarea
      v-if="isActive"
      :model-value="modelValue"
      @update:model-value="$emit('update:modelValue', $event)"
      @pointerdown.stop
      label="Custom HTML"
      auto-grow
      rows="8"
      variant="outlined"
      spellcheck="false"
      class="custom-html-editor"
    />

    <div
      v-else-if="!isHtmlEmpty"
      v-html="modelValue"
    />
    <div v-else>
      {{ modelValue }}
    </div>
  </div>
</template>

<script>
import { isHtmlEmpty } from '@/utils/helpers';
import { defineComponent } from 'vue'

export default defineComponent({
  name: 'CustomHtmlEditor',

  props: {
    modelValue: {
      type: String,
      default: '',
    },
    isActive: {
      type: Boolean,
      default: false,
    },
  },

  computed: {
    isHtmlEmpty() {
      if (!this.modelValue) return true

      const div = document.createElement('div')
      div.innerHTML = this.modelValue

      const text = div.textContent
        ?.replace(/\u00a0/g, ' ')
        .trim()

      return !text
    },
  },

  emits: ['update:modelValue'],
})
</script>

<style scoped>
.custom-html-editor :deep(textarea) {
  font-family: Consolas, Monaco, 'Courier New', monospace;
  font-size: 13px;
  line-height: 1.45;
}
</style>