<template>
  <v-menu
    v-model="menuOpen"
    :close-on-content-click="false"
    location="bottom"
  >
    <template #activator="{ props }">
      <v-btn
        v-bind="props"
        title="Link"
        :color="isLinkActive ? 'black' : ''"
        @click="openMenu"
      >
        <v-icon v-if="isPhoneLinkActive">mdi-phone</v-icon>
        <v-icon v-else-if="isMailLinkActive">mdi-email</v-icon>
        <v-icon v-else>mdi-link</v-icon>
      </v-btn>
      <v-btn
        title="Remove link"
        :class="isLinkActive ? '' : 'fake-disabled'"
        @click="removeLinkFromMenu"
      >
        <v-icon v-if="isPhoneLinkActive">mdi-phone-off</v-icon>
        <v-icon v-else-if="isMailLinkActive">mdi-email-off</v-icon>
        <v-icon v-else>mdi-link-off</v-icon>
      </v-btn>
    </template>

    <v-card width="320" class="pa-3">
      <v-select
        v-model="linkType"
        label="Link type"
        density="compact"
        variant="outlined"
        hide-details
        :items="linkTypeOptions"
        class="mb-3"
      />

      <v-text-field
        v-model="linkInput"
        :label="linkInputLabel"
        density="compact"
        variant="outlined"
        hide-details
        autofocus
        class="mb-3"
        @keydown.enter.prevent="applyLinkFromMenu"
      />

      <div class="d-flex justify-space-between">
        <v-btn
          variant="text"
          :disabled="!isLinkActive"
          @click="removeLinkFromMenu"
        >
          Remove
        </v-btn>

        <div>
          <v-btn variant="text" @click="menuOpen = false">
            Cancel
          </v-btn>

          <v-btn color="black" variant="flat" @click="applyLinkFromMenu">
            Apply
          </v-btn>
        </div>
      </div>
    </v-card>
  </v-menu>
</template>

<script>
import { Extension } from '@tiptap/vue-3';
import { getMarkRange } from '@tiptap/core';
import Link from '@tiptap/extension-link';


// removes rel="noopener noreferrer nofollow" from links.
// https://github.com/iliyaZelenko/tiptap-vuetify/issues/250
export const CustomLink = Link.extend({
  addOptions() {
    return {
      openOnClick: false,
      linkOnPaste: true,
      autolink: true,
      protocols: ['tel', 'mailto'],
      HTMLAttributes: {
        target: '_blank',
        class: null,
        // rel: 'noopener noreferrer nofollow',
      },
      validate: undefined,
    }
  },
})

// adds style to links
export const StyledLink = Extension.create({
  name: "styledLink",

  addOptions: {
    types: ["link"]
  },

  addGlobalAttributes() {
    return [
      {
        types: this.options.types,
        attributes: {
          color: {
            default: null,
            renderHTML: () => {
              return {
                style: `font-family:Roboto,sans-serif;color:#257886;text-decoration:underline;`,
              };
            },
          }
        }
      }
    ];
  },
});

export default {
  name: 'LinkMenu',

  props: {
    editor: {
      type: Object,
      required: true,
    },
  },

  data() {
    return {
      menuOpen: false,
      linkType: 'url',
      linkInput: '',
      linkTypeOptions: [
        { title: 'Regular link', value: 'url' },
        { title: 'Phone', value: 'phone' },
        { title: 'Email', value: 'email' },
      ],
    }
  },

  computed: {
    currentLinkHref() {
      return this.editor?.getAttributes('link').href || ''
    },

    isLinkActive() {
      return this.editor?.isActive('link')
    },

    isPhoneLinkActive() {
      return this.isLinkActive && this.currentLinkHref.startsWith('tel:')
    },

    isMailLinkActive() {
      return this.isLinkActive && this.currentLinkHref.startsWith('mailto:')
    },

    linkInputLabel() {
      if (this.linkType === 'phone') return 'Phone number'
      if (this.linkType === 'email') return 'Email address'
      return 'URL'
    },
  },

  methods: {
    openMenu() {
      const href = this.currentLinkHref
      const selectedText = this.getSelectedText()

      if (href.startsWith('tel:')) {
        this.linkType = 'phone'
        this.linkInput = href.replace('tel:', '')
      } else if (href.startsWith('mailto:')) {
        this.linkType = 'email'
        this.linkInput = href.replace('mailto:', '')
      } else if (href) {
        this.linkType = 'url'
        this.linkInput = href
      } else {
        this.linkType = 'url'
        this.linkInput = selectedText
      }

      this.menuOpen = true
    },

    applyLinkFromMenu() {
      const value = this.linkInput.trim()

      if (value === '') {
        this.removeLinkFromMenu()
        return
      }

      let href = ''

      if (this.linkType === 'phone') {
        href = `tel:${this.normalizePhoneNumber(value)}`
      } else if (this.linkType === 'email') {
        href = `mailto:${this.normalizeEmailAddress(value)}`
      } else {
        href = this.normalizeUrl(value)
      }

      this.applyLink(href)
      this.menuOpen = false
    },

    applyLink(href) {
      this.editor
        .chain()
        .focus()
        .extendMarkRange('link')
        .setLink({ href })
        .run()
    },

    removeLinkFromMenu() {
      this.removeCurrentLink()
      this.menuOpen = false
    },

    removeCurrentLink() {
      const { state, view } = this.editor
      const { empty } = state.selection
      const linkType = state.schema.marks.link
      const href = this.currentLinkHref

      if (!empty) {
        this.editor
          .chain()
          .focus()
          .unsetMark('link')
          .run()

        return
      }

      const range = getMarkRange(state.selection.$from, linkType, { href })

      if (!range) {
        return
      }

      view.dispatch(
        state.tr.removeMark(range.from, range.to, linkType)
      )
    },

    getSelectedText() {
      const { from, to } = this.editor.state.selection

      if (from === to) {
        return ''
      }

      return this.editor.state.doc.textBetween(from, to, ' ').trim()
    },

    normalizeUrl(url) {
      const trimmedUrl = url.trim()

      if (/^www\./i.test(trimmedUrl)) {
        return `https://${trimmedUrl}`
      }

      return trimmedUrl
    },

    normalizePhoneNumber(phone) {
      return phone
        .trim()
        .replace(/\s+/g, '')
        .replace(/[()-]/g, '')
    },

    normalizeEmailAddress(email) {
      return email.trim()
    },
  },
}
</script>

<style lang="css" scoped>

.fake-disabled {
  pointer-events: none;
  opacity: 0.35;
}

</style>