<template>
  <div style="border: black solid 2px; border-radius: 5px" v-if="editor && isActive" class="d-flex justify-center flex-wrap pb-2 pt-1" id="buttons" :style="{'background-color': backgroundColor}">
    <v-defaults-provider :defaults="defaults">
      <div style="flex-basis: 100%; display: flex;justify-content: center; border-bottom: 2px solid black">
        <v-btn title="Add column before" @click="editor.chain().focus().addColumnBefore().run()">
          <v-icon>mdi-table-column-plus-before</v-icon>
        </v-btn>
        <v-btn title="Add column after" @click="editor.chain().focus().addColumnAfter().run()">
          <v-icon>mdi-table-column-plus-after</v-icon>
        </v-btn>
        <v-btn title="Delete column" @click="editor.chain().focus().deleteColumn().run()">
          <v-icon>mdi-table-column-remove</v-icon>
        </v-btn>
        <v-btn title="Add row before" @click="editor.chain().focus().addRowBefore().run()">
          <v-icon>mdi-table-row-plus-before</v-icon>
        </v-btn>
        <v-btn title="Add row after" @click="editor.chain().focus().addRowAfter().run()">
          <v-icon>mdi-table-row-plus-after</v-icon>
        </v-btn>
        <v-btn title="Delete row" @click="editor.chain().focus().deleteRow().run()">
          <v-icon>mdi-table-row-remove</v-icon>
        </v-btn>
        <v-btn title="Merge cells" @click="editor.chain().focus().mergeCells().run()">
          <v-icon>mdi-table-merge-cells</v-icon>
        </v-btn>
        <v-btn title="Split cell" @click="editor.chain().focus().splitCell().run()">
          <v-icon>mdi-table-split-cell</v-icon>
        </v-btn>
      </div>
      <v-btn title="Bold" :color="editor.isActive('bold') ? 'black' : ''" @click="editor.chain().focus().toggleBold().run()">
        <v-icon>mdi-format-bold</v-icon>
      </v-btn>
      <v-btn title="Italic" :color="editor.isActive('italic') ? 'black' : ''" @click="editor.chain().focus().toggleItalic().run()">
        <v-icon>mdi-format-italic</v-icon>
      </v-btn>
      <v-btn title="Orange" :color="editor.isActive('textStyle', {color: '#fb4f00'}) ? 'black' : ''" @click="editor.chain().focus().toggleColor('#fb4f00').run()">
        <v-icon>mdi-format-color-fill</v-icon>
      </v-btn>
      <LinkMenu :editor="editor" />
      <v-btn title="Subscript" :color="editor.isActive('subscript') ? 'black' : ''" @click="editor.chain().focus().toggleSubscript().run()">
        <v-icon>mdi-format-subscript</v-icon>
      </v-btn>
      <v-btn title="Superscript" :color="editor.isActive('superscript') ? 'black' : ''" @click="editor.chain().focus().toggleSuperscript().run()">
        <v-icon>mdi-format-superscript</v-icon>
      </v-btn>
      <div style="flex-basis: 100%; display: flex;justify-content: center">
        <v-btn title="Undo" @click="editor.chain().focus().undo().run()">
          <v-icon>mdi-undo</v-icon>
        </v-btn>
        <v-btn title="Redo" @click="editor.chain().focus().redo().run()">
          <v-icon>mdi-redo</v-icon>
        </v-btn>
      </div>
    </v-defaults-provider>
  </div>
  <editor-content :editor="editor" />
</template>

<script>
import Document from '@tiptap/extension-document'
import Gapcursor from '@tiptap/extension-gapcursor'
import Paragraph from '@tiptap/extension-paragraph'
import Table from '@tiptap/extension-table'
import TableCell from '@tiptap/extension-table-cell'
import TableHeader from '@tiptap/extension-table-header'
import TableRow from '@tiptap/extension-table-row'
import Text from '@tiptap/extension-text'
import {Editor, EditorContent} from '@tiptap/vue-3'
import StarterKit from "@tiptap/starter-kit";
import Subscript from "@tiptap/extension-subscript";
import Superscript from "@tiptap/extension-superscript";
import Highlight from "@tiptap/extension-highlight";
import TextStyle from "@tiptap/extension-text-style";
import {HardBreak} from "@tiptap/extension-hard-break";
import TextAlign from "@tiptap/extension-text-align";
import {CustomLink, StyledLink, Color} from "@/components/text/TextEditor.vue";
import Italic from "@tiptap/extension-italic";
import LinkMenu from '@/components/text/LinkMenu.vue';

export default {
  components: {
    EditorContent,
    LinkMenu
  },

  props: {
    modelValue: {
      type: String,
      default: '',
    },
    isActive: {
      type: Boolean,
      default: false
    },
    backgroundColor: {
      type: String,
    }
  },

  data() {
    return {
      defaults: {
        VBtn: {
          variant: 'text'
        }
      },
      editor: null,
      buttons: [
        { title: 'bold',icon: 'mdi-format-bold', active: 'bold',},
        { title: '',icon: '', active: '',},
      ],
    }
  },

  watch: {
    modelValue(value) {
      // HTML
      // const isSame = this.editor.getHTML() === value

      // JSON
      const isSame = JSON.stringify(this.editor.getJSON()) === JSON.stringify(value)

      if (isSame) {
        return
      }

      this.editor.commands.setContent(value, false)
    },
  },

  mounted() {
    const CustomItalic = Italic.extend({
      renderHTML({HTMLAttributes}) {
        return ['i', HTMLAttributes, 0]
      }
    });
    this.editor = new Editor({
      extensions: [
        StarterKit,
        Document,
        Paragraph,
        Text,
        Subscript,
        Superscript,
        Highlight,
        CustomLink,
        StyledLink,
        TextStyle,
        CustomItalic,
        HardBreak.extend({
          addKeyboardShortcuts() {
            return {
              Enter: () => this.editor.commands.setHardBreak()
            }
          }
        }),
        // color example: https://codesandbox.io/s/cz6ro?file=/src/App.vue
        Color,
        TextAlign.configure({
          types: ['heading', 'paragraph'],
        }),
        Gapcursor,
        Table.configure({
          resizable: true,
        }),
        TableRow,
        TableHeader,
        TableCell,
      ],
      content: this.modelValue,
      onUpdate: () => {
        // HTML
        // this.$emit('update:modelValue', this.editor.getHTML());

        // JSON
        this.$emit('update:modelValue', this.editor.getJSON())
      },
    })
  },

  beforeUnmount() {
    this.editor.destroy()
  },
}
</script>

<style lang="scss">
.ProseMirror {
  table {
    border-collapse: collapse;
    table-layout: fixed;
    width: 100%;
    margin: 0;
    overflow: hidden;

    td,
    th {
      min-width: 1em;
      border: 2px solid #ced4da;
      padding: 3px 5px;
      vertical-align: top;
      box-sizing: border-box;
      position: relative;

      > * {
        margin-bottom: 0;
      }
    }

    th {
      font-weight: bold;
      text-align: left;
      background-color: #f1f3f5;
    }

    .selectedCell:after {
      z-index: 2;
      position: absolute;
      content: "";
      left: 0; right: 0; top: 0; bottom: 0;
      background: rgba(200, 200, 255, 0.4);
      pointer-events: none;
    }

    .column-resize-handle {
      position: absolute;
      right: -2px;
      top: 0;
      bottom: -2px;
      width: 4px;
      background-color: #adf;
      pointer-events: none;
    }

    p {
      margin: 0;
    }
  }
}

.tableWrapper {
  padding: 1rem 0;
  overflow-x: auto;
}

.resize-cursor {
  cursor: ew-resize;
  cursor: col-resize;
}

#buttons {
  margin: 5px 0 10px 0;
}
</style>
