import {Charset} from "@/types/Charset";
import {Language} from "@/types/Language";
import {Country} from "@/types/Country";

export default function chooseCharset(country: Country, language: Language): Charset {
    if (country === Country.LT) return Charset.LIT;
    else if (language === Language.RUS) return Charset.RU;
    else if (country === Country.LV) return Charset.LAT;
    else if (country === Country.EE) return Charset.EST;
    else return Charset.DEFAULT;
}
